 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 // Train and save the model at startup
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Model", "churn-model.zip");

 Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);

 var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

 var pipeline = mlContext.Transforms.Conversion.MapValue<string, bool>("Label",
         new[] {
             new KeyValuePair<string, bool>("Yes", true),
             new KeyValuePair<string, bool>("No", false)
         },
         inputColumnName: nameof(CustomerData.Churned))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(CustomerData.Age),
         nameof(CustomerData.Income),
         "RegionEncoded",
         nameof(CustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 // Use train/test split when there's enough data; otherwise train on all rows
 var rowCount = (int)mlContext.Data.CreateEnumerable<CustomerData>(dataView, reuseRowObject: false).LongCount();
 ITransformer model;

 if (rowCount >= 20)
 {
     var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
     model = pipeline.Fit(split.TrainSet);

     var predictions = model.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
 }
 else
 {
     Console.WriteLine($"Dataset has {rowCount} rows — too few for train/test split. Training on full dataset.");
     model = pipeline.Fit(dataView);
 }

 mlContext.Model.Save(model, dataView.Schema, modelPath);

 // Register the pooled prediction engine (thread-safe for web)
 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest request) =>
 {
     var input = new CustomerData
     {
         Age = request.Age,
         Income = request.Income,
         Region = request.Region,
         PurchaseHistory = request.PurchaseHistory
     };

     var prediction = pool.Predict(input);
     return Results.Ok(new
     {
         Churned = prediction.PredictedLabel,
         Probability = prediction.Probability,
         Score = prediction.Score
     });
 });

 app.Run();

 // --- Model classes ---

 public class CustomerData
 {
     [LoadColumn(0)]
     public float Age { get; set; }

     [LoadColumn(1)]
     public float Income { get; set; }

     [LoadColumn(2)]
     public string Region { get; set; } = string.Empty;

     [LoadColumn(3)]
     public float PurchaseHistory { get; set; }

     [LoadColumn(4)]
     public string Churned { get; set; } = string.Empty;
 }

 public class ChurnPrediction
 {
     [ColumnName("PredictedLabel")]
     public bool PredictedLabel { get; set; }

     public float Probability { get; set; }

     public float Score { get; set; }
 }

 public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);
